const body = $input.first().json.body || $input.first().json;
const { action, messages, model, apiKey, temperature } = body;

if (!apiKey) {
  return [{ json: { error: 'apiKey requis' } }];
}

const headers = {
  'Authorization': 'Bearer ' + apiKey,
  'Content-Type': 'application/json'
};

try {

  // ── Lister les modèles disponibles ─────────────────────────────────────────
  if (action === 'listModels') {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://albert.api.etalab.gouv.fr/v1/models',
      headers,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });
    if (response.statusCode >= 400) {
      return [{ json: { error: 'Albert API erreur ' + response.statusCode } }];
    }
    const data = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
    return [{ json: data }];
  }

  // ── Générer du contenu ──────────────────────────────────────────────────────
  if (!messages) {
    return [{ json: { error: 'messages requis' } }];
  }

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://albert.api.etalab.gouv.fr/v1/chat/completions',
    headers,
    body: JSON.stringify({
      model: model,
      messages: messages,
      temperature: temperature || 0.3,
      max_tokens: 3000
    }),
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });

  if (response.statusCode >= 400) {
    return [{ json: { error: 'Albert API erreur ' + response.statusCode + ': ' + JSON.stringify(response.body).substring(0, 300) } }];
  }

  const data = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
  return [{ json: data }];

} catch(e) {
  return [{ json: { error: e.message } }];
}
